107	func TestNode_ResolvesExecRunByID_ScopedToProject(t *testing.T) {
108		root := t.TempDir()
109		projA := filepath.Join(root, "proj-a")
110		projB := filepath.Join(root, "proj-b")
111	
112		const sharedRunID = "exec-20260502T220000-abc1"
113		seedExecRunProject(t, projA, sharedRunID, ddxexec.StatusSuccess)
114		seedExecRunProject(t, projB, sharedRunID, ddxexec.StatusFailed)
115	
116		r := &Resolver{WorkingDir: projA}
117		q := &queryResolver{r}
118	
119		// ctx=B → status from B's record.
120		ctxB := WithWorkingDir(context.Background(), projB)
121		got, err := q.Node(ctxB, sharedRunID)
122		if err != nil {
123			t.Fatalf("Node(B): %v", err)
124		}
125		if got == nil {
126			t.Fatal("Node(B) returned nil; expected B's run")
127		}
128		runGot, ok := got.(*ExecutionRun)
129		if !ok {
130			t.Fatalf("Node(B) returned %T, want *ExecutionRun", got)
131		}
132		if runGot.Status != ddxexec.StatusFailed {
133			t.Fatalf("CROSS-PROJECT LEAK: ctx=B got status %q (want %q)", runGot.Status, ddxexec.StatusFailed)
134		}
135	
136		// ctx=A → status from A's record.
137		ctxA := WithWorkingDir(context.Background(), projA)
138		gotA, err := q.Node(ctxA, sharedRunID)
139		if err != nil {
140			t.Fatalf("Node(A): %v", err)
141		}
142		runA, ok := gotA.(*ExecutionRun)
143		if !ok || runA.Status != ddxexec.StatusSuccess {
144			t.Fatalf("Node(A) returned %v / want status success", gotA)
145		}
146	
147		// Unknown run id returns nil, no error.
148		miss, err := q.Node(ctxA, "exec-does-not-exist")
149		if err != nil {
150			t.Fatalf("Node(unknown exec) error: %v", err)
151		}
152		if miss != nil {
153			t.Fatalf("Node(unknown exec) want nil, got %v", miss)
154		}
155	}
